function worldPaths(){return `<rect x="0" y="0" width="1000" height="520" fill="#eef5fb"/>`+WORLDP.map(d=>`<path d="${d}" fill="#e6ecf2" stroke="#c2cedb" stroke-width="0.4"/>`).join("");}
function geoSelect(c){geoCountry=c;render();}
function geoBack(){geoCountry=null;render();}
function renderGeo(){
  const byc={};
  visible().forEach(([t,c])=>{(byc[c.geo||'US']=byc[c.geo||'US']||[]).push([t,c]);});
  if(geoCountry && byc[geoCountry]){
    const list=byc[geoCountry].sort((a,b)=>(b[1].mc||0)-(a[1].mc||0));
    const tot=list.reduce((s,[t,c])=>s+(c.mc||0),0);
    const chips=list.map(([t,c])=>`<div class="gco" onclick="openDrill('${t}')"><span class="gdot" style="background:${EXPC[c.exp]||'#999'}"></span><b>${t}</b><span class="gnm">${esc(c.n)}</span><span class="gmc">${fmtMC(c.mc)}</span></div>`).join('');
    return `<div class="note"><button class="pbtn" onclick="geoBack()">← Back to world map</button>  <b>${geoCountry}</b> — ${list.length} companies · ${fmtMC(tot)} combined market cap. Click any company to drill in.</div><div class="gcgrid">${chips}</div>`;
  }
  let g=worldPaths();
  const countries=Object.keys(byc);
  const P={};
  countries.forEach(c=>{const ctr=GEOC[c]||[500,270];const tot=byc[c].reduce((s,[t,cc])=>s+(cc.mc||0),0);const r=Math.max(9,Math.min(38,Math.sqrt(tot)/16));P[c]={x:ctr[0],y:ctr[1],ox:ctr[0],oy:ctr[1],r,tot};});
  for(let it=0;it<90;it++){
    for(let i=0;i<countries.length;i++)for(let j=i+1;j<countries.length;j++){
      const A=P[countries[i]],B=P[countries[j]];let dx=B.x-A.x,dy=B.y-A.y;let d=Math.sqrt(dx*dx+dy*dy)||1;
      const need=A.r+B.r+34; if(d<need){const push=(need-d)/2;dx/=d;dy/=d;A.x-=dx*push;A.y-=dy*push;B.x+=dx*push;B.y+=dy*push;}
    }
    countries.forEach(c=>{const N=P[c];N.x+=(N.ox-N.x)*0.06;N.y+=(N.oy-N.y)*0.06;N.x=Math.max(20,Math.min(980,N.x));N.y=Math.max(30,Math.min(500,N.y));});
  }
  countries.sort((a,b)=>byc[b].length-byc[a].length).forEach(country=>{
    const N=P[country]; const list=byc[country];
    if(Math.abs(N.x-N.ox)>1||Math.abs(N.y-N.oy)>1) g+=`<line x1="${N.ox.toFixed(1)}" y1="${N.oy.toFixed(1)}" x2="${N.x.toFixed(1)}" y2="${N.y.toFixed(1)}" stroke="#9fb4c9" stroke-width="0.7" stroke-dasharray="2 2"/><circle cx="${N.ox.toFixed(1)}" cy="${N.oy.toFixed(1)}" r="1.6" fill="#6b7f96"/>`;
    g+=`<g class="bub" onclick="geoSelect('${country}')"><circle cx="${N.x.toFixed(1)}" cy="${N.y.toFixed(1)}" r="${N.r.toFixed(1)}" fill="#1d4ed82e" stroke="#1d4ed8" stroke-width="1.6"/><text class="lbl" x="${N.x.toFixed(1)}" y="${(N.y+N.r+13).toFixed(1)}" font-size="11.5" text-anchor="middle" font-weight="800" fill="#0f172a">${country}</text><text class="lbl" x="${N.x.toFixed(1)}" y="${(N.y+N.r+25).toFixed(1)}" font-size="10" text-anchor="middle" fill="#475569">${list.length} cos</text></g>`;
  });
  return mapTools("Each bubble = a country, sized by its companies' combined market cap (nudged apart where they overlap; dotted line = true location). Click a country to list its companies.")+svgWrap(1000,520,g);
}
let netMode='all';
function setNetMode(m){netMode=m;render();}
function renderNetwork(){
  const comps=CO();
  const allEdges=(DATA.relationships||[]).filter(e=>comps[e[0]]||comps[e[1]]);
  if(!allEdges.length)return '<div class="note">No mapped relationships for this sector yet.</div>';
  const deg={}; allEdges.forEach(e=>{deg[e[0]]=(deg[e[0]]||0)+1;deg[e[1]]=(deg[e[1]]||0)+1;});
  const supc={}; allEdges.filter(e=>e[2]==='supplies').forEach(e=>{supc[e[0]]=(supc[e[0]]||0)+1;});
  const TYP=['owns','invests','supplies','customer','rival','partner'];
  let edges=allEdges;
  if(TYP.includes(netMode)) edges=allEdges.filter(e=>e[2]===netMode);
  else if(netMode==='hubs'){ edges=allEdges.filter(e=>deg[e[0]]>=2&&deg[e[1]]>=2); }
  else if(netMode==='holdings'){ const held=new Set(Object.keys(comps).filter(k=>comps[k].hold)); edges=allEdges.filter(e=>held.has(e[0])||held.has(e[1])); }
  // filter bar
  const modes=[['all','All'],['hubs','Hubs (backbone)'],...(hasHolds()?[['holdings','◆ Holdings web']]:[]),['owns','Owns'],['invests','Invests'],['supplies','Supplies'],['customer','Customers'],['rival','Rivals'],['partner','Partners']];
  const fbar=`<div class="netf">${modes.map(([k,l])=>`<button class="nfb${k==netMode?' on':''}" onclick="setNetMode('${k}')">${l}</button>`).join('')}</div>`;
  // caption: most connected + biggest supplier
  const topConn=Object.entries(deg).sort((a,b)=>b[1]-a[1]).slice(0,5).map(([k,n])=>`<b>${esc(k)}</b> (${n})`).join(', ');
  const topSup=Object.entries(supc).sort((a,b)=>b[1]-a[1]).slice(0,3).map(([k,n])=>`<b>${esc(k)}</b> (${n})`).join(', ');
  if(!edges.length)return fbar+`<div class="note">No <b>${netMode}</b> links in ${VLABEL[cur]}.</div>`;
  const nodes={}; const add=id=>{if(!nodes[id])nodes[id]={id,ext:!comps[id],c:comps[id]};};
  edges.forEach(e=>{add(e[0]);add(e[1]);});
  const ids=Object.keys(nodes), n=ids.length;
  function tierOf(id){const c=comps[id]; return c?(c.tier||9):9;}
  ids.sort((a,b)=>tierOf(a)-tierOf(b) || (deg[b]||0)-(deg[a]||0) || a.localeCompare(b));
  const S=Math.max(560,Math.min(1180,360+n*14)), W=S, H=S, cx=W/2, cy=H/2, R=S/2-92;
  ids.forEach((id,i)=>{const ang=-Math.PI/2 + i/n*2*Math.PI; nodes[id].x=cx+Math.cos(ang)*R; nodes[id].y=cy+Math.sin(ang)*R; nodes[id].ang=ang;});
  const TY={owns:'#7c3aed',invests:'#1d4ed8',supplies:'#0891b2',customer:'#16a34a',rival:'#dc2626',partner:'#d97706',jv:'#d97706',deploys:'#16a34a',holding:'#64748b','spun-from':'#64748b'};
  const el=edges.map(e=>{const A=nodes[e[0]],B=nodes[e[1]]; if(!A||!B)return ''; const mx=(A.x+B.x)/2,my=(A.y+B.y)/2, cpx=mx+(cx-mx)*0.55, cpy=my+(cy-my)*0.55;
    return `<path d="M${A.x.toFixed(0)} ${A.y.toFixed(0)} Q${cpx.toFixed(0)} ${cpy.toFixed(0)} ${B.x.toFixed(0)} ${B.y.toFixed(0)}" fill="none" stroke="${TY[e[2]]||'#cbd5e1'}" stroke-width="1.3" opacity=".5"/>`;}).join('');
  const nd=ids.map(id=>{const N=nodes[id],c=N.c,dg=deg[id]||1, r=Math.max(4,Math.min(12,4+dg*0.7));
    const right=Math.cos(N.ang)>=0, lx=N.x+Math.cos(N.ang)*(r+5), ly=N.y+Math.sin(N.ang)*(r+5)+3, anc=right?'start':'end', col=N.ext?'#94a3b8':(EXPC[c.exp]||'#999');
    return `<g class="bub" onclick="${N.ext?'':`openDrill('${id}')`}"><circle cx="${N.x.toFixed(0)}" cy="${N.y.toFixed(0)}" r="${r.toFixed(0)}" fill="${col}33" stroke="${col}" stroke-width="1.6"/><text class="lbl" x="${lx.toFixed(0)}" y="${ly.toFixed(0)}" font-size="9.5" text-anchor="${anc}" fill="${N.ext?'#64748b':'#0f172a'}">${esc(id)}</text></g>`;}).join('');
  const leg=Object.entries(TY).filter(([k])=>TYP.includes(k)).map(([k,c])=>`<span style="color:${c};font-weight:700">— ${k}</span>`).join('  ');
  const cap=`<div class="note">Relationship wheel — companies on the ring (grouped by value-chain tier), links drawn as chords. Bubble size = number of connections. <b>Most connected:</b> ${topConn}. <b>Biggest supplier:</b> ${topSup||'—'}. Click a company to drill in.<div style="margin-top:5px;font-size:10.5px">${leg}</div></div>`;
  return fbar+cap+`<div class="maptools"><span class="mut">Scroll to zoom · drag to pan</span><button class="pbtn" onclick="resetPZ()">Reset view</button></div>`+svgWrap(W,H,el+nd);
}
function renderTreemap(){
  const W=1000,H=560; const rows=visible().filter(([t,c])=>c.mc>0);
  if(!rows.length)return '<div class="note">No market-cap data to map.</div>';
  const tiers={}; rows.forEach(([t,c])=>{(tiers[c.tier]=tiers[c.tier]||[]).push([t,c]);});
  const tks=Object.keys(tiers).sort((a,b)=>a-b); const grand=rows.reduce((s,[t,c])=>s+tmw(c),0);
  const names=V().tierNames; let y=0,out='';
  tks.forEach(tk=>{const list=tiers[tk].sort((a,b)=>tmw(b[1])-tmw(a[1]));const tot=list.reduce((s,[t,c])=>s+tmw(c),0);const rh=Math.max(54,tot/grand*H);let x=0;
    out+=`<rect x="0" y="${y}" width="${W}" height="${rh}" fill="none" stroke="#e2e8f0"/>`;
    list.forEach(([t,c])=>{const bw=tmw(c)/tot*W;
      out+=`<g class="bub" onclick="openDrill('${t}')"><rect x="${x}" y="${y}" width="${Math.max(0,bw-2)}" height="${rh-2}" fill="${EXPC[c.exp]||'#999'}33" stroke="${EXPC[c.exp]||'#999'}"/>${(bw>46&&rh>30)?`<text class="lbl" x="${x+6}" y="${y+19}" font-size="11" font-weight="700" fill="#0f172a">${t}</text><text class="lbl" x="${x+6}" y="${y+33}" font-size="9" fill="#475569">${fmtMC(c.mc)}</text>`:(bw>18?`<text class="lbl" x="${x+3}" y="${y+rh/2+3}" font-size="8.5" fill="#0f172a">${t}</text>`:'')}</g>`;
      x+=bw;});
    out+=`<text class="lbl" x="${W-8}" y="${y+15}" text-anchor="end" font-size="11" font-weight="800" fill="#1e293b">${esc(names[tk-1]||('Tier '+tk))}</text>`;
    y+=rh;});
  return mapTools("Box size = <b>sector-attributable market cap</b> (market cap × sector purity) so mega-cap suppliers like NVDA/TSLA don't swamp the pure-plays. Grouped by value-chain tier. Label shows the company's full market cap. Zoom to read smaller boxes; click to drill.")+svgWrap(W,y,out);
}
function stageOf(c){const p=(c.profit||'').toLowerCase(); if(p.includes('profitable')||p.includes('cash-generative')||p.includes('cash generative'))return 2; if(c.rev>0)return 1; return 0;}
function renderMaturity(){
  const W=1000,H=540,padL=64,padB=48,padT=18,padR=24,plotW=W-padL-padR,plotH=H-padT-padB;
  const rows=visible().filter(([t,c])=>c.mc>0); if(!rows.length)return '<div class="note">No data.</div>';
  const stages=['Pre-revenue','Scaling','Profitable']; const X=s=>padL+(s+0.5)/3*plotW;
  const ymax=Math.max(...rows.map(([t,c])=>c.mc)); const lg=x=>Math.log10(Math.max(50,x));
  const Y=mc=>padT+plotH-((lg(mc)-lg(50))/((lg(ymax)-lg(50))||1))*plotH;
  let g='';
  stages.forEach((s,i)=>{g+=`<line x1="${X(i)}" y1="${padT}" x2="${X(i)}" y2="${padT+plotH}" stroke="#eef2f6"/><text x="${X(i)}" y="${H-22}" font-size="12" text-anchor="middle" font-weight="700" fill="#475569">${s}</text>`;});
  [100,1000,10000,100000].forEach(val=>{if(val<=ymax*1.1)g+=`<line x1="${padL}" y1="${Y(val)}" x2="${padL+plotW}" y2="${Y(val)}" stroke="#eef2f6"/><text x="${padL-8}" y="${Y(val)+3}" font-size="9.5" text-anchor="end" fill="#94a3b8">${val>=1000?(val/1000)+'B':val+'M'}</text>`;});
  const cnt={}; let bub='';
  rows.forEach(([t,c])=>{const s=stageOf(c);cnt[s]=(cnt[s]||0)+1;const k=cnt[s];const jit=((k*61)%210)-105;const x=X(s)+jit,y=Y(c.mc),r=Math.max(4,Math.min(17,Math.sqrt(c.mc)/14));
    bub+=`<g class="bub" onclick="openDrill('${t}')"><circle cx="${x}" cy="${y}" r="${r}" fill="${EXPC[c.exp]||'#999'}33" stroke="${EXPC[c.exp]||'#999'}" stroke-width="1.3"/><text class="lbl" x="${x}" y="${y-r-3}" font-size="8.5" text-anchor="middle" fill="#334155">${t}</text></g>`;});
  const inner=`<text x="16" y="${H/2}" font-size="11" fill="#64748b" font-weight="700" transform="rotate(-90 16 ${H/2})">Valuation (log) →</text>${g}${bub}`;
  return mapTools("Commercialization stage (x) vs. valuation (y, log market cap). <b>Top-left = pre-revenue but richly valued = most speculative</b>; bottom-right = profitable & cheaper. Zoom/drag to explore; click to drill.")+svgWrap(W,H,inner);
}

/* ---------- COMPS ---------- */
const COLS=[
  {k:'tkr',l:'Ticker'},{k:'n',l:'Company'},{k:'tier',l:'Tier'},
  {k:'mc',l:'Mkt cap'},{k:'evs',l:'EV/Sales'},{k:'evsF',l:'Fwd EV/S'},
  {k:'grth',l:'Growth'},{k:'gm',l:'GM'},{k:'rating',l:'Street'},{k:'pt',l:'PT'},{k:'score',l:'Score'},{k:'buzz',l:'Buzz'}
];
function cellVal(t,c,k){
  switch(k){case 'tkr':return t;case 'n':return c.n;case 'tier':return c.tier;
    case 'mc':return c.mc;case 'evs':return evs(c);case 'evsF':return evsF(c);
    case 'grth':return c.grth;case 'gm':return c.gm;case 'score':return score(c);
    case 'rating':return c.street?c.street.rating:null;
    case 'pt':return c.street?c.street.ptAvg:null;
    case 'buzz':return c.social?c.social.m:null;}
}
function renderComps(){
  let rows=visible();
  rows.sort((A,B)=>{let a=cellVal(A[0],A[1],sortKey),b=cellVal(B[0],B[1],sortKey);
    if(a==null)return 1;if(b==null)return -1;
    if(typeof a==='string'&&typeof b==='string')return sortDir*a.localeCompare(b);
    return sortDir*((a>b?1:a<b?-1:0));});
  const head=COLS.map(col=>`<th onclick="setSort('${col.k}')" class="${col.k==sortKey?'sorted':''}">${col.l}${col.k==sortKey?(sortDir<0?' ▾':' ▴'):''}</th>`).join('')+'<th>Price</th>';
  const body=rows.map(([t,c])=>{
    const rt=c.street?c.street.rating:'';
    const pt=c.street?('$'+c.street.ptAvg):'';
    const stcls=c.street?'street':'';
    return `<tr onclick="openDrill('${t}')">
      <td class="tk"><span class="starcell ${WATCH.has(t)?'on':''}" title="Star for focus" onclick="event.stopPropagation();toggleWatch('${t}')">${WATCH.has(t)?'★':'☆'}</span>${t}${c.hold?' ◆':''}</td><td class="nm">${esc(c.n)}</td><td>${c.tier}</td>
      <td>${fmtMC(c.mc)}</td><td>${fmtX(evs(c))}</td><td class="${evsF(c)?'fwd':''}">${fmtX(evsF(c))}</td>
      <td>${pctNM(c.grth)}</td><td>${pctNM(c.gm)}</td>
      <td class="${stcls}">${esc(rt)||'—'}</td><td class="${stcls}">${pt||'—'}</td>
      <td><span class="scb" style="--w:${score(c)||0}%">${score(c)??'—'}</span></td><td class="${c.social&&c.social.m>=20?'buzzhot':''}">${buzzCell(c)}</td><td class="livep" ${c.pub?`data-live="${t}"`:''}>${c.pub?'…':'—'}</td></tr>`;
  }).join('');
  return `<div class="note">Sorted by <b>${COLS.find(c=>c.k==sortKey).l}</b>. <span class="fwd">Fwd EV/S</span> and Street columns populate when you feed me a note → drop one in Research_Inbox. Click a row to drill in.</div>
    <table class="comps"><thead><tr>${head}</tr></thead><tbody>${body}</tbody></table>`;
}
function setSort(k){if(sortKey===k)sortDir*=-1;else{sortKey=k;sortDir=(k==='n'||k==='tkr'||k==='rating')?1:-1;}render();}

/* ---------- RANK & VALUE ---------- */
function lean(c){ if(!c.sc)return null; const[g,m,h,v,e]=c.sc; return Math.round(g*0.30+m*0.15+h*0.20+v*0.20+e*0.15); }
function leanTag(L){ return L==null?{t:'-',cls:''}:L>=65?{t:'Lean Buy',cls:'lb'}:L>=45?{t:'Hold / Watch',cls:'lh'}:{t:'Pass',cls:'lp'}; }
function leanWhy(c){ const labs=['growth','margin','health','value','exposure']; const sc=c.sc||[]; if(sc.length<5)return ''; const idx=[0,1,2,3,4].sort((a,b)=>sc[b]-sc[a]); return `+${labs[idx[0]]} ${sc[idx[0]]} / -${labs[idx[4]]} ${sc[idx[4]]}`; }
function peerMedEVS(){ const xs=Object.values(CO()).filter(c=>c.pub&&c.rev>0&&evs(c)!=null&&evs(c)<50).map(c=>evs(c)).sort((a,b)=>a-b); return xs.length?xs[Math.floor(xs.length/2)]:null; }
let sK=1,sX=0,sY=0;
function applyScat(){const g=document.getElementById('scatg');if(g)g.setAttribute('transform',`translate(${sX} ${sY}) scale(${sK})`);}
function resetScat(){sK=1;sX=0;sY=0;applyScat();}
function initScatter(){
  const svg=document.getElementById('scatter'); if(!svg)return;
  const W=760,H=430; applyScat(); svg.style.cursor='grab';
  let moved=false,drag=false,lx=0,ly=0,dnx=0,dny=0;
  svg.onwheel=(e)=>{e.preventDefault();const r=svg.getBoundingClientRect();
    const mx=(e.clientX-r.left)/r.width*W, my=(e.clientY-r.top)/r.height*H;
    const f=e.deltaY<0?1.15:1/1.15, nk=Math.max(0.35,Math.min(10,sK*f));
    sX=mx-(mx-sX)*(nk/sK); sY=my-(my-sY)*(nk/sK); sK=nk; applyScat();};
  svg.onpointerdown=(e)=>{drag=true;moved=false;lx=e.clientX;ly=e.clientY;dnx=e.clientX;dny=e.clientY;svg.style.cursor='grabbing';};
  svg.onpointermove=(e)=>{if(!drag)return;const r=svg.getBoundingClientRect();
    if(Math.abs(e.clientX-dnx)+Math.abs(e.clientY-dny)>5)moved=true;
    sX+=(e.clientX-lx)/r.width*W; sY+=(e.clientY-ly)/r.height*H; lx=e.clientX;ly=e.clientY; applyScat();};
  window.addEventListener('pointerup',()=>{drag=false;svg.style.cursor='grab';});
  svg.addEventListener('click',(e)=>{if(moved){e.stopPropagation();e.preventDefault();}},true);
}
function renderRank(){
  let rows=visible().filter(([t,c])=>c.sc);
  rows.sort((a,b)=>lean(b[1])-lean(a[1]));
  const body=rows.map(([t,c],i)=>{ const L=lean(c),tag=leanTag(L);
    return `<tr onclick="openDrill('${t}')"><td>${i+1}</td><td class="tk">${t}${c.hold?' ◆':''}</td><td class="nm">${esc(c.n)}</td>
      <td><span class="lean ${tag.cls}">${tag.t}</span></td><td><span class="scb" style="--w:${L}%">${L}</span></td>
      <td>${fmtX(evs(c))}</td><td>${pctNM(c.grth)}</td><td class="nm mut">${leanWhy(c)}</td></tr>`; }).join('');
  const lb=`<table class="comps"><thead><tr><th>#</th><th>Ticker</th><th>Company</th><th>Lean</th><th>Lean score</th><th>EV/Sales</th><th>Growth</th><th>Top driver / drag</th></tr></thead><tbody>${body}</tbody></table>`;
  return `<div class="note"><b>Lean</b> is a transparent weighting of the 5-axis scorecard (growth 30% / health 20% / value 20% / margin 15% / exposure 15%) — a starting-point ranking to pressure-test, <b>not investment advice</b>. Scores are estimates. The scatter plots quality vs. valuation for public names with revenue; click any point or row to drill in.</div>
    ${scatterSVG(rows)}${lb}`;
}
function scatterSVG(rows){
  const W=760,H=430,padL=54,padR=20,padT=24,padB=44, plotW=W-padL-padR, plotH=H-padT-padB;
  const pts=rows.filter(([t,c])=>c.pub&&c.rev>0&&evs(c)!=null&&evs(c)<=25);
  const excluded=rows.length-pts.length;
  const xmax=25, ymax=100;
  const X=v=>padL+Math.min(v,xmax)/xmax*plotW;
  const Y=v=>padT+plotH-(v/ymax)*plotH;
  const med=peerMedEVS()||5;
  // gridlines
  let g='';
  [0,5,10,15,20,25].forEach(v=>{g+=`<line x1="${X(v)}" y1="${padT}" x2="${X(v)}" y2="${padT+plotH}" stroke="#eef2f6"/><text x="${X(v)}" y="${H-26}" font-size="10" fill="#94a3b8" text-anchor="middle">${v}x</text>`;});
  [0,25,50,75,100].forEach(v=>{g+=`<line x1="${padL}" y1="${Y(v)}" x2="${padL+plotW}" y2="${Y(v)}" stroke="#eef2f6"/><text x="${padL-8}" y="${Y(v)+3}" font-size="10" fill="#94a3b8" text-anchor="end">${v}</text>`;});
  // median valuation line + score 50 line (quadrants)
  g+=`<line x1="${X(med)}" y1="${padT}" x2="${X(med)}" y2="${padT+plotH}" stroke="#cbd5e1" stroke-dasharray="4 3"/>`;
  g+=`<line x1="${padL}" y1="${Y(50)}" x2="${padL+plotW}" y2="${Y(50)}" stroke="#cbd5e1" stroke-dasharray="4 3"/>`;
  g+=`<text x="${padL+6}" y="${padT+12}" font-size="10" fill="#16a34a" font-weight="700">Cheap + high quality</text>`;
  g+=`<text x="${padL+plotW-6}" y="${padT+12}" font-size="10" fill="#d97706" text-anchor="end" font-weight="700">Expensive (priced up)</text>`;
  g+=`<text x="${padL+plotW-6}" y="${padT+plotH-6}" font-size="10" fill="#dc2626" text-anchor="end" font-weight="700">Expensive + weak</text>`;
  const bub=pts.map(([t,c])=>{ const r=Math.max(4,Math.min(20,Math.sqrt((c.mc||100))/12)); const x=X(evs(c)),y=Y(lean(c));
    return `<g class="bub" onclick="openDrill('${t}')"><circle cx="${x}" cy="${y}" r="${r}" fill="${EXPC[c.exp]||'#999'}33" stroke="${EXPC[c.exp]||'#999'}" stroke-width="1.5"/><text x="${x}" y="${y-r-2}" font-size="9" fill="#475569" text-anchor="middle" font-weight="600">${t}</text></g>`; }).join('');
  return `<div class="scatbar"><span class="mut">Scroll to zoom · drag to pan</span><button class="pbtn" onclick="resetScat()">Reset view</button></div><div class="scatwrap"><div class="axlabel-y">Quality (lean score) →</div><svg viewBox="0 0 ${W} ${H}" class="scatter" id="scatter"><g id="scatg">${g}${bub}</g></svg>
    <div class="axlabel-x">Valuation: EV / Sales → (dashed = peer median ${med.toFixed(1)}x)</div>
    ${excluded?`<div class="mut" style="font-size:11px">${excluded} pre-revenue / private names not plotted (no EV/Sales) — see leaderboard below.</div>`:''}</div>`;
}

/* ---------- CATALYSTS ---------- */
function renderCat(){
  let cats=(V().catalysts||[]).slice();
  if(holdOnly||pubOnly||q){const vis=new Set(visible().map(x=>x[0]));cats=cats.filter(c=>!c[1]||vis.has(c[1]));}
  const rows=cats.map(c=>`<div class="cat"><div class="catd">${esc(c[0])}</div>
    <div class="catb"><div class="catt">${c[1]?`<span class="tk" onclick="openDrill('${c[1]}')">${c[1]}</span> `:''}${esc(c[2])}</div>
    <div class="catw">${esc(c[3]||'')}</div></div></div>`).join('');
  return `<div class="note">Dated catalysts for ${VLABEL[cur]}. Click a ticker to drill in.</div><div class="catlist">${rows||'<i>No catalysts.</i>'}</div>`;
}

/* ---------- COMPARE (radar) ---------- */
function findCo(t){for(const vk in DATA.verticals){if(DATA.verticals[vk].companies[t])return DATA.verticals[vk].companies[t];}return null;}
function inCmp(t){return cmp.includes(t);}
function toggleCmp(t){ if(inCmp(t)) cmp=cmp.filter(x=>x!==t); else { if(cmp.length>=5) return; cmp.push(t);} if(curTab!=='compare')render(); else render(); }
function clearCmp(){cmp=[];render();}
const PRESETS=[
  {k:'gx',l:'⚡ Growth × Exposure',d:'highest growth that is also a pure-play',f:c=>(c.sc?c.sc[0]+c.sc[4]:0)},
  {k:'vh',l:'💰 Cheap × Healthy',d:'cheapest names with a solid balance sheet',f:c=>(c.sc?c.sc[3]+c.sc[2]:0)},
  {k:'mh',l:'🛡 Quality (Margin × Health)',d:'best margins + financial health',f:c=>(c.sc?c.sc[1]+c.sc[2]:0)},
  {k:'pp',l:'🚀 Priced for perfection',d:'high growth + expensive (low value score)',f:c=>(c.sc?c.sc[0]+(100-c.sc[3]):0)},
  ...(hasHolds()?[{k:'hold',l:'◆ Your holdings',d:'names you own',f:c=>(c.hold?1:0),hold:true}]:[])
];
function applyPreset(k){
  const p=PRESETS.find(x=>x.k===k);
  let rows=Object.entries(CO()).filter(([t,c])=>c.pub);
  if(p.hold) rows=rows.filter(([t,c])=>c.hold);
  rows.sort((a,b)=>p.f(b[1])-p.f(a[1]));
  cmp=rows.slice(0,5).map(x=>x[0]);
  render();
}
function renderCompare(){
  const sel=cmp.map((t,i)=>({t,c:findCo(t),color:CC[i]})).filter(x=>x.c);
  const legend=sel.length?sel.map(x=>`<span class="lg" style="--c:${x.color}">${x.t}<button onclick="toggleCmp('${x.t}')">×</button></span>`).join(''):'<span class="mut">none selected</span>';
  // picker: current vertical, filtered by search
  const pick=visible().map(([t,c])=>`<span class="pchip${inCmp(t)?' on':''}" onclick="toggleCmp('${t}')" title="${esc(c.n)}">${t}</span>`).join('');
  const radar=sel.length?radarMulti(sel):'<div class="mut" style="padding:40px;text-align:center">Pick up to 5 names below (or use ＋ Add to compare in any drilldown).</div>';
  // table
  const M=[['Market cap',c=>fmtMC(c.mc)],['EV',c=>fmtMC(ev(c))],['Revenue',c=>c.rev!=null?fmtMC(c.rev):'—'],
    ['EV/Sales',c=>fmtX(evs(c))],['Fwd EV/S',c=>evsF(c)?fmtX(evsF(c)):'—'],['Growth',c=>pct(c.grth)],['Gross margin',c=>pct(c.gm)],
    ['Composite',c=>score(c)??'—'],['· Growth',c=>c.sc?c.sc[0]:'—'],['· Margin',c=>c.sc?c.sc[1]:'—'],['· Health',c=>c.sc?c.sc[2]:'—'],
    ['· Value',c=>c.sc?c.sc[3]:'—'],['· Exposure',c=>c.sc?c.sc[4]:'—'],['Street',c=>c.street?esc(c.street.rating):'—'],['PT',c=>c.street?'$'+c.street.ptAvg:'—']];
  let tbl='';
  if(sel.length){
    const head='<th></th>'+sel.map(x=>`<th style="color:${x.color}">${x.t}</th>`).join('');
    const body=M.map(([lab,fn])=>`<tr><td class="ml">${lab}</td>${sel.map(x=>`<td>${fn(x.c)}</td>`).join('')}</tr>`).join('');
    tbl=`<table class="cmptab"><thead><tr>${head}</tr></thead><tbody>${body}</tbody></table>`;
  }
  const presetbar=`<div class="presets"><span class="plabel">Quick compares (${VLABEL[cur]}):</span>${PRESETS.map(p=>`<button class="pbtn" title="${p.d}" onclick="applyPreset('${p.k}')">${p.l}</button>`).join('')}</div>`;
  return presetbar+`<div class="note">Overlay the 5-axis profile of up to 5 names. Axes are 0–100 relative scores: <b>Growth · Margin · Health · Value · Exposure</b>. Shape shows the trade-off; the table shows the actual numbers. <b>Value</b> axis is high = cheap.</div>
    <div class="cmpsel">Comparing: ${legend} ${sel.length?'<button class="clr" onclick="clearCmp()">clear all</button>':''} ${sel.length>=2?'<button class="pbtn" onclick="exportCompare()">⤓ Export comparison PDF</button>':''}</div>
    <div class="cmpgrid"><div class="cmpradar">${radar}</div><div class="cmptblwrap">${tbl}</div></div>
    <div class="cmppick"><div class="sh">Add from ${VLABEL[cur]} ${q?'(filtered)':''}</div><div class="pchips">${pick}</div></div>`;
}
function radarMulti(sel){
  const labs=['Growth','Margin','Health','Value','Exposure'],cx=200,cy=185,R=130;
  function pt(i,r){const a=-Math.PI/2+i*2*Math.PI/5;return [cx+r*Math.cos(a),cy+r*Math.sin(a)];}
  let g='';for(let q2=1;q2<=4;q2++){const pts=labs.map((_,i)=>pt(i,R*q2/4).join(',')).join(' ');g+=`<polygon points="${pts}" fill="none" stroke="#e2e8f0"/>`;}
  labs.forEach((_,i)=>{const[x,y]=pt(i,R);g+=`<line x1="${cx}" y1="${cy}" x2="${x}" y2="${y}" stroke="#eef2f6"/>`;});
  let polys='';
  sel.forEach(x=>{ if(!x.c.sc)return;
    const pts=x.c.sc.map((v,i)=>pt(i,R*Math.max(0,Math.min(100,v))/100).join(',')).join(' ');
    polys+=`<polygon points="${pts}" fill="${x.color}22" stroke="${x.color}" stroke-width="2"/>`;
    polys+=x.c.sc.map((v,i)=>{const[px,py]=pt(i,R*Math.max(0,Math.min(100,v))/100);return `<circle cx="${px}" cy="${py}" r="3" fill="${x.color}"/>`;}).join('');
  });
  const lab=labs.map((l,i)=>{const[x,y]=pt(i,R+22);return `<text x="${x}" y="${y}" font-size="11" fill="#475569" text-anchor="middle" font-weight="600">${l}</text>`;}).join('');
  return `<svg viewBox="0 0 400 390" class="radarBig">${g}${polys}${lab}</svg>`;
}

/* ---------- DRILLDOWN ---------- */
function streetSignal(t,c){
  if(!c.street)return {label:'No recent Street coverage',cls:'sg-mix',why:'no analyst notes ingested for this name yet'};
  const s=c.street,notes=c.streetNotes||[];let raises=0,cuts=0;
  notes.forEach(n=>{if(n.pt&&n.ptPrior){if(n.pt>n.ptPrior)raises++;else if(n.pt<n.ptPrior)cuts++;}});
  const lp=(typeof LIVE!=='undefined'&&LIVE[t])?LIVE[t].p:null;const up=(lp&&s.ptAvg)?(s.ptAvg/lp-1):null;
  const rb=/buy|outperform|overweight|strong/i.test(s.rating||''),rbear=/sell|underperform|underweight|reduce/i.test(s.rating||'');
  let sc=0;if(rb)sc+=1;if(rbear)sc-=2;if(raises>cuts)sc+=1;if(cuts>raises)sc-=1;if(up!=null){if(up>0.25)sc+=1;if(up<0)sc-=1;}
  const why=[`${esc(s.rating||'?')} (${s.nAnalysts||'?'} firms)`];
  if(cuts>raises)why.push(`targets being CUT (${cuts}\u2193 vs ${raises}\u2191)`);
  else if(raises>cuts)why.push(`targets rising (${raises}\u2191 vs ${cuts}\u2193)`);
  if(up!=null)why.push(`${up>=0?'+':''}${Math.round(up*100)}% to avg PT`);
  let label,cls;
  if(sc>=2){label='Street CONFIRMS the bull';cls='sg-bull';}
  else if(sc<=-1){label='Street LEANS AGAINST the bull';cls='sg-bear';}
  else {label='Street MIXED / cooling';cls='sg-mix';}
  return {label,cls,why:why.join(' \u00b7 ')};
}
function renderThesis(t,c){
  if(!c.thesis)return '';
  const sig=streetSignal(t,c);
  const banner=`<div class="sgnl ${sig.cls}"><span class="sgl">Thesis \u21c4 Street: ${sig.label}</span><span class="sgw">${sig.why}</span></div>`;
  const side=(arr,cls)=>arr.map(x=>`<div class="thpt"><div class="thp ${cls}">${esc(x.p)}</div><ul class="thd">${(x.d||[]).map(dd=>`<li>${esc(dd)}</li>`).join('')}</ul></div>`).join('');
  const sc=c.scen||{};
  const row=(k,lab,col)=>sc[k]?`<tr><td class="scl" style="color:${col}">${lab}</td><td class="scd">${esc(sc[k].dir)}</td><td>${esc(sc[k].cond)}</td></tr>`:'';
  return banner+`<div class="repsec">What the market is pricing in</div><div class="implbox">${esc(c.implied||'')}</div>
    <div class="repsec">Scenarios</div><table class="scentab"><thead><tr><th></th><th>Move</th><th>What it takes</th></tr></thead><tbody>${row('bull','Bull','#16a34a')}${row('base','Base','#64748b')}${row('bear','Bear','#dc2626')}</tbody></table>
    <div class="thesisgrid"><div><div class="sh">Bull — and what makes it true</div>${side(c.thesis.bull,'tb')}</div><div><div class="sh">Bear — and what makes it true</div>${side(c.thesis.bear,'tr')}</div></div>`;
}
function openDrill(t){
  const c=CO()[t]; if(!c)return;
  document.getElementById('drillbody').innerHTML=drill(t,c);
  document.getElementById('drill').classList.add('open');
  if(c.pub){fetchLive([t]);drillNews(t);}
}
function closeDrill(){document.getElementById('drill').classList.remove('open');}
function stat(l,v){return `<div class="st"><div class="stl">${l}</div><div class="stv">${v}</div></div>`;}
function drill(t,c){
  const e=ev(c);
  const stats=[
    stat('Market cap',fmtMC(c.mc)),stat('Enterprise value',fmtMC(e)),
    stat('Revenue (ttm)',revNM(c.rev)),stat('EV / Sales',c.rev?fmtX(evs(c)):'<span class=mut>n/m</span>'),
    stat('Fwd EV/Sales',evsF(c)?fmtX(evsF(c)):'<span class=mut>needs estimates</span>'),
    stat('Rev growth',pctNM(c.grth)),stat('Gross margin',pctNM(c.gm)),stat('P/E',esc(c.pe||'—')),
    stat('Profitability',esc(c.profit||'—')),stat('Balance sheet',esc(c.cash||'—')),
    stat('Sector purity',c.pur!=null?Math.round(c.pur*100)+'%':'—'),
    stat('Composite score',score(c)??'—'),
    stat('Reddit buzz 24h',c.social?`${c.social.m} mentions ${c.social.m>(c.social.m0||0)?'\u25b2':''} · #${c.social.rk} on Reddit`:'<span class=mut>—</span>')
  ].join('');
  const radar=radarSVG(c.sc);
  const exp=`<span class="pill" style="background:${EXPC[c.exp]||'#999'}">${EXPL[c.exp]||c.exp}</span>`;
  const hold=c.hold?`<div class="holdbar">◆ Your position: ${c.hold[0]} sh · <span data-livemv="${t}" data-qty="${c.hold[0]}">$${c.hold[1].toLocaleString()}</span> market value</div>`:'';
  // Street panel
  let street;
  if(c.street){const s=c.street;
    const lp=(typeof LIVE!=='undefined'&&LIVE[t])?LIVE[t].p:null; const up=(lp&&s.ptAvg)?Math.round((s.ptAvg/lp-1)*100):null;
    const notes=(c.streetNotes||[]).map(n=>{const arr=n.ptPrior?(n.pt>n.ptPrior?' <span class="up">\u25b2</span>':(n.pt<n.ptPrior?' <span class="down">\u25bc</span>':'')):''; return `<div class="snote"><span class="snf">${esc(n.firm||'')}</span> <b>${esc(n.rating||'')}</b> ${n.pt?('$'+n.pt):'<span class=mut>no PT</span>'}${n.ptPrior?` <span class="mut">(was $${n.ptPrior})</span>`:''}${arr} <span class="mut">${esc(n.date||'')}</span></div>`;}).join('');
    street=`<div class="street"><div class="sh">Street view <span class="src">${esc(s.source||'')}</span></div>
      <div class="strow"><b>${esc(s.rating||'—')}</b> · avg PT $${s.ptAvg??'—'} ${s.ptHigh?`(range $${s.ptLow}\u2013$${s.ptHigh}, ${s.nAnalysts||'?'} firms)`:''}${up!=null?` · <b class="${up>=0?'up':'down'}">${up>=0?'+':''}${up}% to target</b>`:''}</div>
      ${s.basis?`<div class="mut">Basis: ${esc(s.basis)}</div>`:''}
      ${notes?`<div class="snotes">${notes}</div>`:''}</div>`;
  } else {
    street=`<div class="street empty">No Street data yet. Drop a sell-side note in <b>Research_Inbox</b> or paste it in chat → ratings, PTs and forward estimates land here.</div>`;
  }
  // earnings power
  let ep='';
  if(c.estimates){const es=c.estimates;
    const rows=[['FY+1E',es.revFY1],['FY+2E',es.revFY2],['FY+3E',es.revFY3]].filter(r=>r[1]!=null)
      .map(r=>`<tr><td>${r[0]} revenue</td><td>${fmtMC(r[1])}</td></tr>`).join('');
    const pm=peerMedEVS(); let imp='';
    if(pm&&es.revFY2){const impEV=es.revFY2*pm,cur=ev(c),up=cur?Math.round((impEV/cur-1)*100):null;
      imp=`<tr><td>Implied EV @ peer median ${pm.toFixed(1)}x on FY+2E rev</td><td><b>${fmtMC(impEV)}</b></td></tr>
      ${up!=null?`<tr><td>vs current EV ${fmtMC(cur)}</td><td class="${up>=0?'up':'down'}"><b>${up>=0?'+':''}${up}%</b></td></tr>`:''}`;}
    ep=`<div class="ep"><div class="sh">Earnings power <span class="src">Street estimates + peer multiple</span></div>
      <table class="eptab">${rows}<tr><td>Fwd EV/Sales (on FY+2E)</td><td><b>${fmtX(evsF(c))}</b></td></tr>${imp}</table>
      <div class="mut" style="font-size:10.5px;margin-top:4px">Implied value applies the vertical's median public EV/Sales to FY+2 revenue — a simple peer-multiple cross-check, not a price target.</div></div>`;
  }
  const watch=(c.watch||[]).map(w=>`<li>${esc(w)}</li>`).join('');
  const cats=(V().catalysts||[]).filter(x=>x[1]===t).map(x=>`<li><b>${esc(x[0])}</b> — ${esc(x[2])}</li>`).join('');
  return `<div class="dh"><div><span class="dtk">${t}</span> ${c.pub?`<span class="livechip" data-live="${t}">…</span>`:''} ${exp} ${c.pub?'':'<span class="pill priv">Private</span>'}</div>
      <div class="dn">${esc(c.n)} · <span class="mut">${esc(c.seg||'')}</span>${c.conf==='est'?' <span class="estbadge" title="figures are estimates">est</span>':''}</div>${c.valnote?`<div class="vnote">Valuation basis: ${esc(c.valnote)}</div>`:''}</div>
    <button class="cmpbtn ${WATCH.has(t)?'starred':''}" onclick="toggleWatch('${t}')">${WATCH.has(t)?'★ Focused':'☆ Focus'}</button> <button class="cmpbtn" onclick="toggleCmp('${t}')">${inCmp(t)?'✓ In compare':'＋ Add to compare'}</button> <button class="cmpbtn alt" onclick="exportSingle('${t}')">⤓ Export PDF</button>
    ${hold}
    ${c.pub?`<div class="repsec" style="margin-top:10px">Latest news <span class="src">${liveOn?'MT Newswires':'Yahoo Finance'}</span></div><div id="drillnews" class="mut" style="font-size:11px">${liveOn?'loading…':((c.news&&c.news.length)?c.news.slice(0,5).map(a=>`<div class="dnews"><span class="ndate">${esc(a.pub||'')}${a.pub&&a.date?' · ':''}${esc(a.date||'')}</span><div class="dnh"><a href="${a.link}" target="_blank" rel="noopener">${esc(a.h||'')}</a></div></div>`).join(''):'No recent headlines.')}</div>`:''}
    <div class="dgrid">${stats}</div>
    <div class="drow">${street}${ep}</div>
    <div class="dcols">
      <div class="dcol">${c.thesis?'':`<div class="sh">Bull</div><p>${esc(c.bull||'—')}</p><div class="sh">Bear / key debate</div><p>${esc(c.bear||'—')}</p>`}<div class="sh">Connections</div><p class="mut">${esc(c.conns||'—')}</p></div>
      <div class="dcol"><div class="sh">Scorecard</div>${radar}
        <div class="sh">What to watch</div><ul>${watch||'<li class=mut>—</li>'}</ul>
        ${cats?`<div class="sh">Catalysts</div><ul>${cats}</ul>`:''}</div>
    </div>${renderThesis(t,c)}${drillAwards(c)}${drillNotes(t)}`;
}
function radarSVG(sc){
  if(!sc)return '<div class=mut>—</div>';
  const labs=['Growth','Margin','Health','Value','Exposure'],cx=110,cy=95,R=70;
  function pt(i,r){const a=-Math.PI/2+i*2*Math.PI/5;return [cx+r*Math.cos(a),cy+r*Math.sin(a)];}
  let grid='';for(let g=1;g<=4;g++){const pts=labs.map((_,i)=>pt(i,R*g/4).join(',')).join(' ');grid+=`<polygon points="${pts}" fill="none" stroke="#e2e8f0"/>`;}
  const poly=sc.map((v,i)=>pt(i,R*Math.max(0,Math.min(100,v))/100).join(',')).join(' ');
  const labels=labs.map((l,i)=>{const[x,y]=pt(i,R+16);return `<text x="${x}" y="${y}" font-size="9" fill="#64748b" text-anchor="middle">${l}</text>`;}).join('');
  return `<svg viewBox="0 0 220 200" class="radar"><polygon points="${grid?'':''}"/>${grid}<polygon points="${poly}" fill="#1d4ed833" stroke="#1d4ed8" stroke-width="1.5"/>${labels}</svg>`;
}

/* ---------- PDF export: tear sheet + comparison ---------- */
function openReport(html){document.getElementById('report').innerHTML=html;document.getElementById('repoverlay').classList.add('open');document.body.classList.add('printing');}
function closeReport(){document.getElementById('repoverlay').classList.remove('open');document.body.classList.remove('printing');}
function printReport(){window.print();}
function repStat(l,v){return `<div class="rs"><div class="rsl">${l}</div><div class="rsv">${v}</div></div>`;}
function scoreBars(sc){const labs=['Growth','Margin','Health','Value','Exposure'];
  return `<svg viewBox="0 0 250 132" class="repchart">`+labs.map((l,i)=>{const v=sc?sc[i]:0,y=6+i*25;
    return `<text x="0" y="${y+12}" font-size="10" fill="#475569">${l}</text><rect x="72" y="${y+3}" width="150" height="13" rx="2" fill="#eef2f6"/><rect x="72" y="${y+3}" width="${(150*v/100).toFixed(0)}" height="13" rx="2" fill="#1d4ed8"/><text x="226" y="${y+13}" font-size="9" fill="#0f172a">${v}</text>`;}).join('')+`</svg>`;}
function valBar(c){const e=evs(c)||0,pm=peerMedEVS()||0,mx=Math.max(e,pm,1)*1.25;
  const row=(lab,v,col,y)=>`<text x="0" y="${y+11}" font-size="10" fill="#475569">${lab}</text><rect x="110" y="${y+2}" width="${(120*v/mx).toFixed(0)}" height="13" rx="2" fill="${col}"/><text x="${(112+120*v/mx).toFixed(0)}" y="${y+13}" font-size="9" fill="#0f172a">${v.toFixed(1)}x</text>`;
  return `<svg viewBox="0 0 250 70" class="repchart"><text x="0" y="12" font-size="10" font-weight="700" fill="#1e293b">EV / Sales vs peer median</text>${row(c?'this':'',e,'#1d4ed8',22)}${row('peers',pm,'#94a3b8',44)}</svg>`;}
function peersOf(t,c){return Object.entries(CO()).filter(([k,x])=>k!==t&&x.tier===c.tier&&x.mc).sort((a,b)=>(b[1].mc)-(a[1].mc)).slice(0,6);}
function buildSingleReport(t){const c=CO()[t];if(!c)return '';const e=ev(c);
  const stats=[repStat('Market cap',fmtMC(c.mc)),repStat('Enterprise value',fmtMC(e)),repStat('Revenue',revNM(c.rev)),repStat('EV / Sales',c.rev?fmtX(evs(c)):'n/m'),
    repStat('Fwd EV/Sales',evsF(c)?fmtX(evsF(c)):'—'),repStat('Rev growth',pctNM(c.grth)),repStat('Gross margin',pctNM(c.gm)),repStat('P/E',esc(c.pe||'—')),
    repStat('Profitability',esc(c.profit||'—')),repStat('Balance sheet',esc(c.cash||'—')),repStat('Sector purity',c.pur!=null?Math.round(c.pur*100)+'%':'—'),repStat('Composite / Lean',`${score(c)??'—'} / ${lean(c)??'—'}`)].join('');
  let street='';if(c.street){const sx=c.street;street=`<div class="repsec">Street view</div><p style="font-size:12px">${esc(sx.rating||'')} · PT $${sx.ptAvg??'—'} ${sx.ptHigh?`(range $${sx.ptLow}-$${sx.ptHigh})`:''} <span style="color:#94a3b8">${esc(sx.source||'')} ${esc(sx.date||'')}</span><br>${esc(sx.basis||'')}</p>`;}
  let ep='';if(c.estimates){const es=c.estimates,pm=peerMedEVS();const er=[['FY+1E',es.revFY1],['FY+2E',es.revFY2],['FY+3E',es.revFY3]].filter(r=>r[1]!=null).map(r=>`${r[0]} ${fmtMC(r[1])}`).join(' · ');
    let imp='';if(pm&&es.revFY2){const iv=es.revFY2*pm,up=e?Math.round((iv/e-1)*100):null;imp=` → implied EV ${fmtMC(iv)} @ ${pm.toFixed(1)}x (${up>=0?'+':''}${up}% vs current)`;}
    ep=`<div class="repsec">Earnings power</div><p style="font-size:12px">${er}${imp}</p>`;}
  const watch=(c.watch||[]).map(w=>`<li>${esc(w)}</li>`).join('');
  const cats=(V().catalysts||[]).filter(x=>x[1]===t).map(x=>`<li><b>${esc(x[0])}</b> — ${esc(x[2])}</li>`).join('');
  const peers=peersOf(t,c);
  const ptbl=`<table class="reptbl"><thead><tr><th>Peer (Tier ${c.tier})</th><th>Mkt cap</th><th>EV/Sales</th><th>Growth</th><th>GM</th><th>Score</th></tr></thead><tbody>`+
    [[t,c],...peers].map(([k,x])=>`<tr class="${k===t?'reprow-self':''}"><td>${k} ${x.hold?'◆':''}</td><td>${fmtMC(x.mc)}</td><td>${fmtX(evs(x))}</td><td>${pctNM(x.grth)}</td><td>${pctNM(x.gm)}</td><td>${score(x)??'—'}</td></tr>`).join('')+`</tbody></table>`;
  return `<div class="rephead"><div class="reptk">${t} ${c.hold?'<span style=\"font-size:13px;color:#d97706\">◆ held</span>':''}</div><div class="repname">${esc(c.n)} — ${esc(c.seg||'')} · ${EXPL[c.exp]||c.exp} exposure · ${VLABEL[cur]}</div><div class="repmeta">Frontier Terminal tear sheet · data as of ${DATA.as_of}${c.conf==='est'?' · figures are internal estimates':''}</div></div>
    <div class="repsec">Snapshot</div><div class="repgrid">${stats}</div>
    <div class="repsec">Profile</div><div class="repcharts"><div>${scoreBars(c.sc)}</div><div>${radarSVG(c.sc)}</div></div>${c.rev?`<div style="margin-top:6px">${valBar(c)}</div>`:''}
    <div class="repsec">Thesis</div><div class="repcols"><div><h4>Bull</h4><p>${esc(c.bull||'—')}</p></div><div><h4>Bear / key debate</h4><p>${esc(c.bear||'—')}</p></div></div>
    ${street}${ep}
    ${watch?`<div class="repsec">What to watch</div><ul>${watch}</ul>`:''}${cats?`<div class="repsec">Catalysts</div><ul>${cats}</ul>`:''}
    <div class="repsec">Connections</div><p style="font-size:12px">${esc(c.conns||'—')}</p>
    <div class="repsec">Peer positioning</div>${ptbl}
    <div class="repfoot">Frontier Industries Intelligence — generated ${DATA.as_of}. Figures are a mix of disclosed data and internal estimates (flagged) and may be approximate; not investment advice.</div>`;
}
function cmpBar(sel,fn,fmt,title){const vals=sel.map(x=>fn(x.c)||0),mx=Math.max(...vals,1),W=250,slot=(W-10)/sel.length,bw=Math.min(46,slot-10);
  let b='';sel.forEach((x,i)=>{const v=vals[i],h=(v/mx)*78,xx=10+i*slot+(slot-bw)/2;b+=`<rect x="${xx.toFixed(0)}" y="${(98-h).toFixed(0)}" width="${bw.toFixed(0)}" height="${h.toFixed(0)}" rx="2" fill="${x.color}"/><text x="${(xx+bw/2).toFixed(0)}" y="110" font-size="8" text-anchor="middle" fill="#475569">${x.t}</text><text x="${(xx+bw/2).toFixed(0)}" y="${(96-h).toFixed(0)}" font-size="8" text-anchor="middle" fill="#0f172a">${fmt(v)}</text>`;});
  return `<div class="repbarc"><div class="repbart">${title}</div><svg viewBox="0 0 ${W} 116">${b}</svg></div>`;}
function buildCompareReport(){const sel=cmp.map((t,i)=>({t,c:findCo(t),color:CC[i]})).filter(x=>x.c);if(sel.length<2)return '';
  const bars=cmpBar(sel,c=>c.mc,fmtMC,'Market cap')+cmpBar(sel,c=>evs(c),v=>v?v.toFixed(1)+'x':'—','EV / Sales')+cmpBar(sel,c=>c.grth!=null?c.grth*100:0,v=>v.toFixed(0)+'%','Rev growth')+cmpBar(sel,c=>c.gm!=null?c.gm*100:0,v=>v.toFixed(0)+'%','Gross margin')+cmpBar(sel,c=>score(c),v=>v,'Composite');
  const M=[['Market cap',c=>fmtMC(c.mc)],['EV',c=>fmtMC(ev(c))],['Revenue',c=>revNM(c.rev)],['EV/Sales',c=>fmtX(evs(c))],['Fwd EV/S',c=>evsF(c)?fmtX(evsF(c)):'—'],['Growth',c=>pctNM(c.grth)],['Gross margin',c=>pctNM(c.gm)],['P/E',c=>esc(c.pe||'—')],['Profitability',c=>esc(c.profit||'—')],['Composite',c=>score(c)??'—'],['Lean',c=>lean(c)??'—'],['Exposure',c=>EXPL[c.exp]||c.exp]];
  const head='<th></th>'+sel.map(x=>`<th style="color:${x.color}">${x.t}</th>`).join('');
  const body=M.map(([l,fn])=>`<tr><td>${l}</td>${sel.map(x=>`<td>${fn(x.c)}</td>`).join('')}</tr>`).join('');
  const bb=sel.map(x=>`<div style="margin-bottom:8px"><h4 style="margin:0;color:${x.color}">${x.t} — ${esc(x.c.n)}</h4><p style="margin:2px 0;font-size:11.5px"><b>Bull:</b> ${esc(x.c.bull||'—')}</p><p style="margin:2px 0;font-size:11.5px"><b>Bear:</b> ${esc(x.c.bear||'—')}</p></div>`).join('');
  return `<div class="rephead"><div class="reptk">Comparison — ${sel.map(x=>x.t).join(' · ')}</div><div class="repname">Frontier Terminal · ${sel.length} companies · data as of ${DATA.as_of}</div></div>
    <div class="repsec">Profile overlay (0-100 scores)</div><div style="text-align:center">${radarMulti(sel)}</div>
    <div class="repsec">Key metrics</div><div class="repbars">${bars}</div>
    <div class="repsec">Side by side</div><table class="reptbl cmpwide"><thead><tr>${head}</tr></thead><tbody>${body}</tbody></table>
    <div class="repsec">Thesis snapshot</div>${bb}
    <div class="repfoot">Frontier Industries Intelligence — generated ${DATA.as_of}. Mix of disclosed data and internal estimates; not investment advice.</div>`;
}
function exportSingle(t){openReport(buildSingleReport(t));}
function exportCompare(){if(cmp.length<2){alert('Pick at least 2 names in Compare first.');return;}openReport(buildCompareReport());}

/* ---------- workspace (localStorage) ---------- */
function lsGet(k,def){try{const v=localStorage.getItem('ft_'+k);return v?JSON.parse(v):def;}catch(e){return def;}}
function lsSet(k,v){try{localStorage.setItem('ft_'+k,JSON.stringify(v));}catch(e){}}
let NOTES=lsGet('notes',{}), WATCH=new Set(lsGet('watch',[]));
function noteOf(t){return NOTES[t]||{};}
function setNote(t,f,v){NOTES[t]=NOTES[t]||{};NOTES[t][f]=v;NOTES[t].reviewed=new Date().toISOString().slice(0,10);lsSet('notes',NOTES);}
function toggleWatch(t){if(WATCH.has(t))WATCH.delete(t);else WATCH.add(t);lsSet('watch',[...WATCH]);render();}
function exportNotes(){try{const b=new Blob([JSON.stringify(NOTES,null,2)],{type:'application/json'});const a=document.createElement('a');a.href=URL.createObjectURL(b);a.download='frontier_notes.json';a.click();}catch(e){}}
function fmtAmt(x){return x>=1e9?'$'+(x/1e9).toFixed(1)+'B':x>=1e6?'$'+(x/1e6).toFixed(0)+'M':'$'+Math.round(x).toLocaleString();}
function drillAwards(c){if(!c.awards||!c.awards.length)return '';return `<div class="repsec">Recent federal awards <span class="src">USASpending</span></div><table class="comps awardtab"><tbody>`+c.awards.slice(0,6).map(a=>`<tr><td class="mut">${esc(a.date||'')}</td><td class="nm">${esc(a.ag||'')}</td><td class="mono">${fmtAmt(a.amt||0)}</td><td class="nm mut">${esc((a.desc||'').slice(0,52))}</td></tr>`).join('')+`</tbody></table>`;}
function drillNotes(t){const nn=noteOf(t);const opt=o=>`<option ${nn.conv===o?'selected':''}>${o}</option>`;
  return `<div class="repsec">Notes & conviction <button class="micro" onclick="toggleWatch('${t}')">${WATCH.has(t)?'\\u2605 on watchlist':'\\u2606 watch'}</button></div>
   <div class="notesbox">
   <div class="nrow"><label>Conviction <select onchange="setNote('${t}','conv',this.value)">${['','High','Med','Low','Trim','Exit'].map(opt).join('')}</select></label>
   <label>Entry <input type="date" value="${nn.entry||''}" onchange="setNote('${t}','entry',this.value)"></label></div>
   <textarea placeholder="Thesis at entry — why you own it" onchange="setNote('${t}','thesis',this.value)">${esc(nn.thesis||'')}</textarea>
   <textarea placeholder="Working notes" onchange="setNote('${t}','note',this.value)">${esc(nn.note||'')}</textarea>
   ${nn.reviewed?`<div class="mut" style="font-size:10px">Last updated ${nn.reviewed}</div>`:''}</div>`;}
/* ---------- DASHBOARD ---------- *//* ---------- DASHBOARD ---------- */
function uniCount(){const set=new Set();for(const vk in DATA.verticals)Object.keys(DATA.verticals[vk].companies).forEach(t=>set.add(t));return set.size;}
function buzzLeaders(nn){const m={};for(const vk in DATA.verticals){const c=DATA.verticals[vk].companies;for(const t in c){const s=c[t].social;if(s&&s.m&&!m[t])m[t]={t,s,c:c[t]};}}return Object.values(m).sort((a,b)=>b.s.m-a.s.m).slice(0,nn);}
function allCats(){const out=[];for(const vk in DATA.verticals)(DATA.verticals[vk].catalysts||[]).forEach(x=>out.push([vk,x[0],x[1],x[2]]));return out;}
function kpi(l,v,sub){return `<div class="kpi"><div class="kpil">${l}</div><div class="kpiv">${v}</div>${sub?`<div class="kpis">${sub}</div>`:''}</div>`;}
function dcard(title,body,extra){return `<div class="dcard"><div class="dch">${title}${extra?`<span class="dchx">${extra}</span>`:''}</div>${body}</div>`;}
function renderDashboard(){
  const holds=heldList();
  const totMV=holds.reduce((a,[vk,t,c])=>a+((c.hold&&c.hold[1])||0),0);
  const kpis=`<div class="kpis">${kpi('Universe',uniCount(),'names across 3 verticals')}${hasHolds()?kpi('Holdings',holds.length,'$'+Math.round(totMV).toLocaleString()+' value'):''}${kpi('Live prices',liveOn?'ON':'OFF',liveOn?'IBKR':'open in Cowork')}${kpi('Data as of',DATA.as_of,'estimates unless Street')}</div>`;
  // holdings snapshot
  let holdCard='';
  if(holds.length){
    const rows=holds.slice().sort((a,b)=>((b[2].hold&&b[2].hold[1])||0)-((a[2].hold&&a[2].hold[1])||0)).map(([vk,t,c])=>{
      const sig=streetSignal(t,c);const lp=(LIVE[t]&&LIVE[t].p)||null;const up=(lp&&c.street&&c.street.ptAvg)?Math.round((c.street.ptAvg/lp-1)*100):null;
      return `<tr onclick="openDrill('${t}')"><td class="tk">${t}</td><td class="livep" data-live="${t}">…</td><td class="${up>0?'up':up<0?'down':''}">${up!=null?((up>0?'+':'')+up+'%'):'—'}</td><td><span class="sgpill ${sig.cls}">${SGSHORT[sig.cls]||'—'}</span></td></tr>`;}).join('');
    holdCard=dcard('Your holdings','<table class="comps dashtab"><thead><tr><th>Ticker</th><th>Price</th><th>To PT</th><th>Thesis⇄Street</th></tr></thead><tbody>'+rows+'</tbody></table>','<button class="pbtn" onclick="setTab(\'holdings\')">Full scorecard →</button>');
  }
  // attention: non-bull street signals
  let alerts='';
  if(holds.length){
    const a=holds.map(([vk,t,c])=>[t,c,streetSignal(t,c)]).filter(x=>x[1].street&&x[2].cls!=='sg-bull');
    alerts=dcard('Needs attention — Street not confirming', a.length?('<ul class="dlist">'+a.map(([t,c,sig])=>`<li onclick="openDrill('${t}')"><b class="tk">${t}</b> <span class="sgpill ${sig.cls}">${SGSHORT[sig.cls]}</span> <span class="mut">${esc(sig.why)}</span></li>`).join('')+'</ul>'):'<div class="mut" style="padding:6px 0">All covered holdings: Street confirms.</div>');
  }
  // buzz leaders
  const bz=buzzLeaders(8);
  const buzzCard=dcard('Reddit buzz — universe leaders','<ul class="dlist">'+bz.map(o=>`<li onclick="openDrill('${o.t}')"><b class="tk">${o.t}</b> <span class="mono">${o.s.m}</span> ${o.s.m>(o.s.m0||0)?'<span class="up">▲</span>':(o.s.m<(o.s.m0||0)?'<span class="down">▼</span>':'')} <span class="mut">${esc(o.c.n)}</span></li>`).join('')+'</ul>');
  // catalysts (holdings first)
  const heldset=new Set(holds.map(x=>x[1]));
  const cats=allCats().sort((a,b)=>(heldset.has(b[2])?1:0)-(heldset.has(a[2])?1:0)).slice(0,7);
  const catCard=dcard('Upcoming catalysts','<ul class="dlist">'+cats.map(([vk,date,tk,ev])=>`<li ${tk?`onclick="openDrill('${tk}')"`:''}><span class="cdate">${esc(date)}</span> ${tk?`<b class="tk">${tk}</b> `:''}<span class="mut">${esc(ev)}</span></li>`).join('')+'</ul>','<button class="pbtn" onclick="setTab(\'catalysts\')">All →</button>');
  // top news
  let newsCard;
  if(!liveOn){const bn=(DATA.news||[]).slice(0,7);newsCard=dcard('Top stories', bn.length?('<ul class="dlist">'+bn.map(a=>`<li onclick="window.open('${a.link}','_blank','noopener')"><b class="tk">${esc(a.tk||'')}</b> <span class="mut">${esc((a.h||'').slice(0,74))}</span></li>`).join('')+'</ul>'):'<div class="mut" style="padding:6px 0">No headlines yet — the daily updater will fill these.</div>','<button class="pbtn" onclick="setTab(\'news\')">News →</button>');}
  else if(!newsItems.length){newsCard=dcard('Top stories', newsLoading?'<div class="mut" style="padding:6px 0">Loading the wire…</div>':'<div class="mut" style="padding:6px 0">News feed unavailable right now.</div>');}
  else{const top=newsItems.slice().sort((a,b)=>impScore(b)-impScore(a)).slice(0,6);
    newsCard=dcard('Top stories today','<ul class="dlist">'+top.map(a=>{const[cl,cc]=newsCatOf(a.metadata);const th=thesisHit(a);return `<li onclick="openDrill('${a.key}')"><span class="ncat ${cc}">${cl}</span> ${th?'<span class="nth">★</span> ':''}<b class="tk">${a.key}</b> <span class="mut">${esc((a.headline||'').slice(0,70))}</span></li>`;}).join('')+'</ul>','<button class="pbtn" onclick="setTab(\'news\')">News →</button>');}
  // what-changed (buzz deltas)
  const ch=[];const cseen={};for(const vk in DATA.verticals){const cc=DATA.verticals[vk].companies;for(const t in cc){const so=cc[t].social;if(so&&so.m!=null&&so.m0!=null&&so.m-so.m0>0&&!cseen[t]){cseen[t]=1;ch.push([t,so.m-so.m0,so.m,cc[t]]);}}}
  ch.sort((a,b)=>b[1]-a[1]);
  const changedCard=dcard('What changed — buzz spikes (24h)', ch.length?('<ul class="dlist">'+ch.slice(0,6).map(([t,dl,m,c])=>`<li onclick="openDrill('${t}')"><b class="tk">${t}</b> <span class="up">\u25b2${dl}</span> <span class="mono">${m}</span> <span class="mut">${esc(c.n)}</span></li>`).join('')+'</ul>'):'<div class="mut" style="padding:6px 0">No buzz spikes.</div>');
  // concentration & exposure
  let concCard='';
  if(holds.length){const tot2=holds.reduce((a,[,,c])=>a+((c.hold&&c.hold[1])||0),0)||1;
    const cr=holds.slice().sort((a,b)=>(b[2].hold[1]||0)-(a[2].hold[1]||0)).slice(0,8).map(([vk,t,c])=>{const p=Math.round((c.hold[1]||0)/tot2*100);return `<div class="concrow" onclick="openDrill('${t}')"><span class="tk" style="min-width:54px">${t}</span><div class="concbar"><div style="width:${p}%"></div></div><span class="mono">${p}%</span></div>`;}).join('');
    const exp={};holds.forEach(([vk,t,c])=>{exp[c.exp]=(exp[c.exp]||0)+(c.hold[1]||0);});
    const mix=Object.entries(exp).sort((a,b)=>b[1]-a[1]).map(([e,v])=>`${EXPL[e]||e} ${Math.round(v/tot2*100)}%`).join(' \u00b7 ');
    concCard=dcard('Concentration & exposure', cr+`<div class="mut" style="margin-top:6px;font-size:10.5px">Exposure mix: ${mix}</div>`);
  }
  // key programs (current vertical)
  const ps=(DATA.programs||[]).filter(p=>p.v===cur);
  const progCard=dcard('Key programs \u2014 '+VLABEL[cur], '<ul class="dlist plist">'+ps.map(p=>`<li><b>${esc(p.n)}</b><div class="ptks">${p.co.filter(t=>CO()[t]).map(t=>`<span class="ptk" onclick="openDrill('${t}')">${t}</span>`).join('')}</div></li>`).join('')+'</ul>');
  // review queue
  const rq=[];for(const t in NOTES){const nn=NOTES[t],c=anyCo(t);if(!c)continue;const stale=!nn.reviewed||(Date.now()-Date.parse(nn.reviewed))>2592e6;if(stale||nn.conv==='Trim'||nn.conv==='Exit')rq.push([t,nn]);}
  const reviewCard=rq.length?dcard('Review queue','<ul class="dlist">'+rq.map(([t,nn])=>`<li onclick="openDrill('${t}')"><b class="tk">${t}</b> ${nn.conv?`<span class="micro">${esc(nn.conv)}</span>`:''} <span class="mut">${nn.reviewed?('updated '+nn.reviewed):'no review yet'}</span></li>`).join('')+'</ul>'):'';
  // ★ focus list (starred names)
  let focusCard='';
  {const fs=[...WATCH].map(t=>{const c=anyCo(t);return c?[t,c]:null;}).filter(Boolean);
   if(fs.length){const frows=fs.map(([t,c])=>{const sig=c.street?streetSignal(t,c):null;const lp=(LIVE[t]&&LIVE[t].p)||null;const up=(lp&&c.street&&c.street.ptAvg)?Math.round((c.street.ptAvg/lp-1)*100):null;
     return `<tr onclick="openDrill('${t}')"><td class="tk">★ ${t}${c.hold?' ◆':''}</td><td class="livep" data-live="${t}">…</td><td class="${up>0?'up':up<0?'down':''}">${up!=null?((up>0?'+':'')+up+'%'):'—'}</td><td>${sig?`<span class="sgpill ${sig.cls}">${SGSHORT[sig.cls]||'—'}</span>`:'<span class="mut">—</span>'}</td></tr>`;}).join('');
     focusCard=dcard('★ Focus list','<table class="comps dashtab"><thead><tr><th>Ticker</th><th>Price</th><th>To PT</th><th>Thesis⇄Street</th></tr></thead><tbody>'+frows+'</tbody></table>','<button class="pbtn" onclick="if(!focusOnly)toggleFocus();setTab(\'comps\')">Filter comps →</button>');
   }else{focusCard=dcard('★ Focus list','<div class="mut" style="padding:6px 0">Star companies (the ☆ on any comps row, or <b>☆ Focus</b> in a drilldown) to pin them here for quick tracking.</div>');}}
  // methodology & sources
  const pv=DATA.provenance||{};
  const methodCard=dcard('Methodology & sources','<table class="comps methtab"><thead><tr><th>Data</th><th>Source</th><th>As of</th><th>Conf</th></tr></thead><tbody>'+Object.entries(pv).map(([k,v])=>`<tr><td class="ml" style="text-transform:capitalize;font-family:inherit">${k}</td><td class="mut" style="font-family:inherit">${esc(v.src)}</td><td class="mut">${esc(v.asof||'')}</td><td><span class="conf cf-${v.conf}">${v.conf}</span></td></tr>`).join('')+'</tbody></table>','<button class="pbtn" onclick="exportNotes()">Export notes</button>');
  const onb=lsGet('onboarded',0)?'':`<div class="onb"><b>\u25c6 Start here:</b> this Dashboard is your daily brief. Open any company for its thesis, Street view, scenarios & your notes. <b>Maps \u2192 Value chain</b>: click a name to trace its specific links. <b>News</b>: live wire, filter to your holdings. <button onclick="lsSet('onboarded',1);render()">Got it</button></div>`;
  const aw=[];for(const vk2 in DATA.verticals){const cc2=DATA.verticals[vk2].companies;for(const t2 in cc2){(cc2[t2].awards||[]).forEach(a=>aw.push({t:t2,amt:a.amt,ag:a.ag,date:a.date,desc:a.desc}));}}
  aw.sort((a,b)=>(String(b.date||'').localeCompare(String(a.date||'')))||((b.amt||0)-(a.amt||0)));
  const awardCard=aw.length?dcard('Recent federal awards','<div style="max-height:320px;overflow:auto"><table class="comps dashtab"><thead><tr><th style="position:sticky;top:0;background:#fff;z-index:1">Co</th><th style="position:sticky;top:0;background:#fff;z-index:1">Agency</th><th style="position:sticky;top:0;background:#fff;z-index:1">Amount</th><th style="position:sticky;top:0;background:#fff;z-index:1">Date</th></tr></thead><tbody>'+aw.slice(0,60).map(a=>`<tr onclick="openDrill('${a.t}')"><td class="tk">${a.t}</td><td class="mut" style="font-family:inherit">${esc((a.ag||'').slice(0,24))}</td><td class="mono">${fmtAmt(a.amt||0)}</td><td class="mut">${esc(a.date||'')}</td></tr>`).join('')+'</tbody></table></div>','<span class="src">USASpending · '+aw.length+'</span>'):'';
  return onb+kpis+`<div class="dashgrid">${focusCard}${awardCard}${changedCard}${holdCard}${alerts}${reviewCard}${newsCard}${buzzCard}${concCard}${progCard}${methodCard}</div>`;
}
/* ---------- HOLDINGS scorecard ---------- */
const SGSHORT={'sg-bull':'Confirms','sg-mix':'Mixed','sg-bear':'Against'};
function renderHoldings(){
  const rows=heldList();
  if(!rows.length)return '<div class="note">No holdings in this dataset.</div>';
  let totMV=rows.reduce((a,[vk,t,c])=>a+((c.hold&&c.hold[1])||0),0);
  rows.sort((a,b)=>((b[2].hold&&b[2].hold[1])||0)-((a[2].hold&&a[2].hold[1])||0));
  const body=rows.map(([vk,t,c])=>{
    const sig=streetSignal(t,c); const lp=(LIVE[t]&&LIVE[t].p)||null;
    const up=(lp&&c.street&&c.street.ptAvg)?Math.round((c.street.ptAvg/lp-1)*100):null;
    const mv=lp?Math.round(lp*c.hold[0]):c.hold[1];
    const ncat=nextCat(vk,t); const buzz=c.social?c.social.m:null;
    const sgs=SGSHORT[sig.cls]||'—';
    return `<tr onclick="openDrill('${t}')">
      <td class="tk">${t}</td><td class="nm">${esc(c.n)}</td><td class="mut">${VLABEL[vk].split(' ')[0]}</td>
      <td>$${Math.round(mv).toLocaleString()}</td>
      <td class="livep" data-live="${t}">…</td>
      <td class="${up>0?'up':up<0?'down':''}">${up!=null?((up>0?'+':'')+up+'%'):'<span class=mut>—</span>'}</td>
      <td><span class="sgpill ${sig.cls}" title="${esc(sig.why)}">${sgs}</span></td>
      <td>${buzz!=null?buzz:'<span class=mut>—</span>'}</td>
      <td>${score(c)??'—'}/${lean(c)??'—'}</td>
      <td class="nm mut">${ncat?(esc(ncat[0])+' — '+esc(ncat[2])):'—'}</td></tr>`;
  }).join('');
  return `<div class="note">Your <b>${rows.length}</b> holdings · total ≈ <b>$${Math.round(totMV).toLocaleString()}</b> (live where available, else last snapshot). Thesis⇄Street: green=Street confirms your bull, yellow=cooling, red=leaning against. Click a row to drill in.</div>
    <table class="comps holdtab"><thead><tr><th>Ticker</th><th>Company</th><th>Sector</th><th>Mkt value</th><th>Price</th><th>Upside to PT</th><th>Thesis⇄Street</th><th>Buzz</th><th>Score/Lean</th><th>Next catalyst</th></tr></thead><tbody>${body}</tbody></table>`;
}
/* ---------- NEWS feed (MT Newswires via Cowork) ---------- */
function anyCo(t){for(const vk in DATA.verticals){if(DATA.verticals[vk].companies[t])return DATA.verticals[vk].companies[t];}return null;}
function newsCatOf(meta){meta=meta||'';
  if(/mergers_acquisitions/.test(meta))return['M&A','nc-ma'];
  if(/new_projects_ventures|contract/.test(meta))return['Contract / Venture','nc-con'];
  if(/analyst_rating|analyst_upgrade|analyst_downgrade|analyst_initiates/.test(meta))return['Analyst','nc-an'];
  if(/equity_debt_offering/.test(meta))return['Capital raise','nc-cap'];
  if(/corporate_earnings|earnings_revision/.test(meta))return['Earnings','nc-ea'];
  if(/operations_update/.test(meta))return['Operations','nc-op'];
  return['Update','nc-ot'];}
async function newsFetch(symbols){const r=await window.cowork.callMcpTool(NEWS_TOOL,{dataset_name:'mt_newswires_north_america',product:'EDGE',symbols,last:45,limit:70});const o=(r&&r.structuredContent)?r.structuredContent:JSON.parse(r.content[0].text);try{return JSON.parse(o.result);}catch(e){return [];}}
function newsUniverse(){const set=new Set();for(const vk in DATA.verticals){const c=DATA.verticals[vk].companies;Object.keys(c).forEach(t=>{if(c[t].pub&&!MUTE.has(t))set.add(t);});}return [...set];}
async function loadNews(force){if(!liveOn)return;if(newsLoading)return;newsLoading=true;newsLoaded=true;render();
  const tks=newsUniverse();const chunks=[];for(let i=0;i<tks.length;i+=30)chunks.push(tks.slice(i,i+30));
  const seen=new Set();const items=[];
  for(const ch of chunks){try{const arr=await newsFetch(ch.join(','));arr.forEach(a=>{if(!a.subkey||seen.has(a.subkey))return;seen.add(a.subkey);items.push(a);});}catch(e){}}
  items.sort((a,b)=>(b.releaseTime||b.date||'').localeCompare(a.releaseTime||a.date||''));
  newsItems=items;newsLoading=false;render();}
function fmtNewsDate(a){const r=a.releaseTime||a.date||'';if(!r)return '';const d=new Date(r);if(isNaN(d))return a.date||'';return d.toLocaleDateString(undefined,{month:'short',day:'numeric'})+' '+d.toLocaleTimeString(undefined,{hour:'numeric',minute:'2-digit'});}
function tickChips(a){const ks=[];if(a.key)ks.push(a.key);(a.related||'').split(/[ ,]+/).forEach(x=>{if(x&&!ks.includes(x))ks.push(x);});
  return ks.filter(k=>anyCo(k)).slice(0,5).map(k=>`<span class="ntk${MUTE.has(k)?' mega':''}" onclick="openDrill('${k}')">${k}</span>`).join('');}
function thesisHit(a){
  const c=anyCo(a.key); if(!c||!c.thesis)return null;
  const hay=((a.headline||'')+' '+(a.body||'')).toLowerCase();
  const bull=c.thesis.bull.filter(p=>(p.kw||[]).some(k=>k&&hay.includes(k))).map(p=>p.p);
  const bear=c.thesis.bear.filter(p=>(p.kw||[]).some(k=>k&&hay.includes(k))).map(p=>p.p);
  return (bull.length||bear.length)?{bull,bear}:null;
}
function impScore(a){const m=(a.metadata||'').toLowerCase(),h=(a.headline||'').toLowerCase();let sc=0;
  if(/mergers_acquisitions/.test(m))sc+=100;
  if(/new_projects_ventures|contract/.test(m)||/\bcontract\b|awarded|\baward\b|\bwins\b|\bwon\b|selected|sole.source/.test(h))sc+=95;
  if(/equity_debt_offering/.test(m)||/offering|prices \$|convertible|raises \$/.test(h))sc+=78;
  if(/analyst_rating|analyst_upgrade|analyst_downgrade|analyst_initiates/.test(m)||/price target|upgrade|downgrade|initiates coverage|raises target|cuts target/.test(h))sc+=74;
  if(/corporate_earnings|earnings_revision/.test(m)||/\bearnings\b|quarterly results|\bguidance\b|raises outlook|cuts outlook|backlog/.test(h))sc+=70;
  if(/operations_update/.test(m))sc+=38;
  if(thesisHit(a))sc+=55;
  if(/approval|\bfaa\b|\bfda\b|certif|milestone|maiden|first flight|delivery|deliver|partnership|joint venture|\border\b|down\s?select|booking/.test(h))sc+=16;
  // noise penalties
  if(/social_buzz|most_active/.test(m))sc-=70;
  if(/\bgainers\b|\bdecliners\b|\bmovers\b|wallstreetbets|social buzz|exchange-traded funds|equity futures|most active|sector etfs?/.test(h))sc-=80;
  return sc;}
function setNewsSort(k){newsSort=k;render();}
function renderNews(){
  if(!liveOn){let bn=(DATA.news||[]).slice();if(newsFocus)bn=bn.filter(a=>WATCH.has(a.tk));if(q)bn=bn.filter(a=>(((a.h||'')+' '+(a.tk||'')).toLowerCase().includes(q)));
    return `<div class="newsmeta">${newsFocus?'★ focus only · ':''}${bn.length} headlines · source: Yahoo Finance · refreshed daily · open inside Cowork for the full MT Newswires wire</div><div class="newslist">`+(bn.length?bn.map(a=>`<div class="nart"><div class="nmeta"><span class="tk">${esc(a.tk||'')}</span> <span class="ndate">${esc(a.pub||'')}${a.pub&&a.date?' · ':''}${esc(a.date||'')}</span></div><div class="nhead"><a href="${a.link}" target="_blank" rel="noopener">${esc(a.h||'')}</a></div></div>`).join(''):'<div class="note">No headlines yet — the daily updater will populate these.</div>')+`</div>`;}
  const cats=[['all','All'],['thesis','\u2605 My thesis'],['nc-con','Contract / Venture'],['nc-ma','M&A'],['nc-cap','Capital raise'],['nc-an','Analyst'],['nc-ea','Earnings'],['nc-op','Operations']];
  const bar=`<div class="newsbar"><div class="newscats">${cats.map(([k,l])=>`<button class="ncf${k===newsCat?' on':''}" onclick="setNewsCat('${k}')">${l}</button>`).join('')}</div>
    <label class="nck"><input type="checkbox" ${newsPrimary?'checked':''} onchange="newsPrimary=this.checked;render()"> Primary only</label>
    <label class="nck"><input type="checkbox" ${newsMega?'checked':''} onchange="toggleMega(this.checked)"> Include mega-caps</label>
    <label class="nck"><input type="checkbox" ${newsFocus?'checked':''} onchange="newsFocus=this.checked;render()"> ★ Focus only</label>
    <span class="newssort"><button class="ncf${newsSort==="time"?" on":""}" onclick="setNewsSort('time')">🕒 Latest</button><button class="ncf${newsSort==="imp"?" on":""}" onclick="setNewsSort('imp')">★ Most important</button></span><button class="pbtn" onclick="loadNews(true)">↻ Refresh</button></div>`;
  if(newsLoading&&!newsItems.length)return bar+`<div class="note">Sweeping the wire for all listed companies…</div>`;
  let items=newsItems.slice();
  if(newsPrimary)items=items.filter(a=>a.isPrimary!==false || anyCo(a.key)&&!MUTE.has(a.key));
  if(newsCat==='thesis')items=items.filter(a=>thesisHit(a));
  else if(newsCat!=='all')items=items.filter(a=>newsCatOf(a.metadata)[1]===newsCat);
  if(q)items=items.filter(a=>(a.headline||'').toLowerCase().includes(q)||(a.key||'').toLowerCase().includes(q));
  if(holdOnly){const held=new Set(heldList().map(x=>x[1])); items=items.filter(a=>held.has(a.key)||((a.related||'').split(/[ ,]+/).some(r=>held.has(r))));}
  if(pubOnly){items=items.filter(a=>{const c=anyCo(a.key);return !c||c.pub;});}
  if(newsFocus){items=items.filter(a=>WATCH.has(a.key)||((a.related||'').split(/[ ,]+/).some(r=>WATCH.has(r))));}
  if(newsSort==='imp'){items=items.filter(a=>impScore(a)>=25);items.sort((a,b)=>{const d=impScore(b)-impScore(a);return d!==0?d:(b.releaseTime||'').localeCompare(a.releaseTime||'');});}
  const list=items.slice(0,200).map(a=>{const[cl,cc]=newsCatOf(a.metadata);const body=(a.body||'').replace(/^[0-9:]+ [AP]M [A-Z]{2,4}, [0-9\/]+ \(MT Newswires\) -- /,'').slice(0,230);
    const th=thesisHit(a);return `<div class="nart"><div class="nmeta"><span class="ncat ${cc}">${cl}</span>${impScore(a)>=85?'<span class="ncrit">★ critical</span>':''}${th?`<span class="nth" title="${esc([...th.bull.map(x=>'BULL: '+x),...th.bear.map(x=>'BEAR: '+x)].join(' · '))}">★ thesis${th.bull.length&&th.bear.length?'':(th.bull.length?' (bull)':' (bear)')}</span>`:''}${tickChips(a)}<span class="ndate">${fmtNewsDate(a)}</span></div>
      <div class="nhead">${esc(a.headline||'')}</div><div class="nbody">${esc(body)}${body.length>=230?'…':''}</div></div>`;}).join('');
  return bar+`<div class="newsmeta">${newsFocus?'★ focus only · ':''}${holdOnly?'◆ holdings only · ':''}${items.length} stories${newsSort==='imp'?' · ranked by importance (deals, contracts, raises, ratings, earnings first)':''} across the investable universe · muting ${newsMega?'nothing':'mega/diversified names ('+[...MUTE].slice(0,6).join(', ')+'…)'} · source: MT Newswires</div><div class="newslist">${list||'<div class="note">No stories match.</div>'}</div>`;
}
function setNewsCat(k){newsCat=k;render();}
function toggleMega(v){newsMega=v;if(v){MUTE.clear();}else{['NVDA','TSLA','PLTR','UBER','QCOM','BA','RTX','LMT','NOC','HII','TXT','TDY','BIDU','D','DUK','SO','NEE','EXC','ETR','PEG'].forEach(x=>MUTE.add(x));}newsLoaded=false;newsItems=[];render();loadNews(true);}
/* drilldown latest news */
async function drillNews(t){if(!liveOn)return;try{const arr=await newsFetch(t);const el=document.getElementById('drillnews');if(!el)return;
  const items=arr.filter(a=>a.key===t).slice(0,5);
  el.innerHTML=items.length?items.map(a=>{const[cl,cc]=newsCatOf(a.metadata);return `<div class="dnews"><span class="ncat ${cc}">${cl}</span> <span class="ndate">${fmtNewsDate(a)}</span><div class="dnh">${esc(a.headline||'')}</div></div>`;}).join(''):'<div class="mut" style="font-size:11px">No recent wire stories.</div>';
}catch(e){}}

/* ---------- boot ---------- */
if(!liveOn){for(const vk in DATA.verticals){const cc=DATA.verticals[vk].companies;for(const t in cc){if(cc[t].px!=null)LIVE[t]={p:cc[t].px,chg:cc[t].chg||0};}}}
renderChrome();render();
window.addEventListener('resize',()=>{if(curTab==='map')drawEdges();});

